module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);
parameter [1:0] state0 = 2'b00;
parameter [1:0] state1 = 2'b01;
parameter [1:0] state2 = 2'b10;
parameter [1:0] state3 = 2'b11;
reg [1:0] state;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= 10'b0;
        valid_out <= 1'b0;
        state <= state0;
    end else if (state == state0) begin
        if (valid_in) begin
            data_out <= data_out + data_in;
            state <= state1;
        end
    end else if (state == state1) begin
        if (valid_in) begin
            data_out <= data_out + data_in;
            state <= state2;
        end
    end else if (state == state2) begin
        if (valid_in) begin
            data_out <= data_out + data_in;
            state <= state3;
        end
    end else if (state == state3) begin
        if (valid_in) begin
            data_out <= data_out + data_in;
            valid_out <= 1'b1;
            state <= state0;
        end
    end
end
endmodule
